import{_ as o,o as i,c as t,a8 as n}from"./chunks/framework.DvHWw5tv.js";const g=JSON.parse('{"title":"useColorUtils","description":"","frontmatter":{},"headers":[],"relativePath":"en/design/hooks/useColorUtils.md","filePath":"en/design/hooks/useColorUtils.md"}'),l={name:"en/design/hooks/useColorUtils.md"};function a(r,e,s,c,d,u){return i(),t("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1776104037000"},[...e[0]||(e[0]=[n('<h1 id="usecolorutils" tabindex="-1">useColorUtils <a class="header-anchor" href="#usecolorutils" aria-label="Permalink to “useColorUtils”">​</a></h1><h3 id="usecolorutils-collection-of-color-utility-functions" tabindex="-1">useColorUtils: Collection of Color Utility Functions <a class="header-anchor" href="#usecolorutils-collection-of-color-utility-functions" aria-label="Permalink to “useColorUtils: Collection of Color Utility Functions”">​</a></h3><h2 id="pain-points" tabindex="-1">Pain Points <a class="header-anchor" href="#pain-points" aria-label="Permalink to “Pain Points”">​</a></h2><p>In modern UI component libraries, color handling is central to visual consistency, yet it often involves scattered, repetitive, and error-prone logic:</p><ul><li>Need to convert hex or rgb colors to <code>rgba</code> with transparency</li><li>Theme or dynamic colors need global injection into <code>:root</code> CSS variables (e.g., <code>--primary-color</code>)</li><li>Plain modes often require adding transparency to theme variables (e.g., <code>rgba(var(--el-color-primary), 0.2)</code>)</li><li>Server-side rendering (SSR) environments cannot access <code>document</code>; global style injection must be handled safely</li><li>Dynamically injected global variables can cause memory leaks or multi-instance pollution if not cleaned up</li></ul><p>These seemingly simple requirements, if implemented disparately across components, lead to inconsistent conversion rules, SSR errors, and style leaks.</p><h2 id="design-goals" tabindex="-1">Design Goals <a class="header-anchor" href="#design-goals" aria-label="Permalink to “Design Goals”">​</a></h2><p><code>useColorUtils</code> is not a traditional reactive Hook but a <strong>pure collection of utility functions</strong> dedicated to providing unified, safe, and reusable implementations for color-related operations. It serves as the underlying foundation for color Hooks like <code>useColorComputed</code>, aiming to:</p><ul><li>Centralize all color conversion and global injection logic</li><li>Ensure SSR compatibility and client-side safety</li><li>Provide automatic cleanup mechanisms to prevent style pollution</li></ul><h2 id="core-utility-functions" tabindex="-1">Core Utility Functions <a class="header-anchor" href="#core-utility-functions" aria-label="Permalink to “Core Utility Functions”">​</a></h2><table tabindex="0"><thead><tr><th>Function</th><th>Responsibility</th><th>Key Features</th></tr></thead><tbody><tr><td><strong>toRGBA</strong></td><td>Converts <code>#xxx</code>, <code>#xxxxxx</code>, or <code>rgb()</code> color to <code>rgba(..., opacity)</code></td><td>Pure string processing, no DOM dependency, fully SSR safe<br>Supports 3-digit and 6-digit hex<br>Returns <code>transparent</code> for invalid input</td></tr><tr><td><strong>applyGlobalColor</strong></td><td>Dynamically injects a color value into <code>:root</code> CSS custom properties</td><td>Client-only (automatically skipped in SSR)<br>Auto-cleans up variable on <code>onUnmounted</code><br>Prevents stale values on multi-instance/switching</td></tr></tbody></table><h2 id="design-highlights" tabindex="-1">Design Highlights <a class="header-anchor" href="#design-highlights" aria-label="Permalink to “Design Highlights”">​</a></h2><ul><li><strong>SSR Friendly</strong>: All DOM-related operations strictly check <code>typeof document !== &#39;undefined&#39;</code>, preventing server-side crashes.</li><li><strong>Automatic Resource Management</strong>: <code>applyGlobalColor</code> registers an <code>onUnmounted</code> cleanup function when injecting global variables, ensuring removal upon component destruction—perfect for dynamic theme switching or multi-instance scenarios.</li><li><strong>Lightweight Pure Functions</strong>: <code>toRGBA</code> has no dependency on Vue reactivity or lifecycle; it&#39;s pure string parsing, safe to call in any environment (setup, utils, or even non-Vue contexts).</li><li><strong>Deep Collaboration with Theme System</strong>: Designed specifically for CSS variables (e.g., <code>var(--btn-color-primary)</code>), easily achieving transparency overlay effects with <code>toRGBA</code>.</li></ul><h2 id="design-value" tabindex="-1">Design Value <a class="header-anchor" href="#design-value" aria-label="Permalink to “Design Value”">​</a></h2><p>Though small, <code>useColorUtils</code> resolves all the &quot;hidden pains&quot; of color handling in component libraries:</p><ul><li>Unifies conversion rules, avoiding disparate implementations across components</li><li>Safely handles SSR and client boundaries</li><li>Automatically cleans up global styles, preventing leaks</li><li>Provides a solid foundation for higher-level color Hooks like <code>useColorComputed</code></li></ul>',16)])])}const p=o(l,[["render",a]]);export{g as __pageData,p as default};
